import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.Pywvta2k.js";const x=JSON.parse('{"title":"朱良春","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/08-朱良春.md","filePath":"tcm-data/05-近现代/08-朱良春.md","lastUpdated":1781084559000}'),r={name:"tcm-data/05-近现代/08-朱良春.md"};function n(s,t,d,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="朱良春" tabindex="-1">朱良春 <a class="header-anchor" href="#朱良春" aria-label="Permalink to &quot;朱良春&quot;">​</a></h1><blockquote><p>朱良春（1917-2015年），江苏镇江人 国医大师，虫类药大师，痹证专家 代表作：《朱良春用药经验集》《虫类药的应用》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字良春</li><li><strong>师承</strong>：章次公（近代名医）</li><li><strong>经历</strong>：南通市中医院院长，创办&quot;南通良春中医药研究所&quot;</li><li><strong>学术地位</strong>：<strong>虫类药研究的泰斗</strong>，&quot;痹证（风湿类疾病）克星&quot;</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-虫类药应用" tabindex="-1">1. 虫类药应用 <a class="header-anchor" href="#_1-虫类药应用" aria-label="Permalink to &quot;1. 虫类药应用&quot;">​</a></h3><p>朱良春是<strong>虫类药应用的第一人</strong>。他常用的虫类药包括：</p><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">功效</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>全蝎</strong></td><td style="text-align:left;">辛，平，有毒</td><td style="text-align:left;">熄风镇痉，通络止痛</td><td style="text-align:left;">痹证、中风</td></tr><tr><td style="text-align:left;"><strong>蜈蚣</strong></td><td style="text-align:left;">辛，温，有毒</td><td style="text-align:left;">熄风镇痉，解毒散结</td><td style="text-align:left;">痹证、肿瘤</td></tr><tr><td style="text-align:left;"><strong>地龙</strong></td><td style="text-align:left;">咸，寒</td><td style="text-align:left;">清热定惊，通络利尿</td><td style="text-align:left;">中风、痹证</td></tr><tr><td style="text-align:left;"><strong>水蛭</strong></td><td style="text-align:left;">咸、苦，平，有毒</td><td style="text-align:left;">破血逐瘀</td><td style="text-align:left;">瘀血重症</td></tr><tr><td style="text-align:left;"><strong>僵蚕</strong></td><td style="text-align:left;">咸、辛，平</td><td style="text-align:left;">祛风定惊，化痰散结</td><td style="text-align:left;">中风、瘰疬</td></tr><tr><td style="text-align:left;"><strong>蝉蜕</strong></td><td style="text-align:left;">甘，寒</td><td style="text-align:left;">散风热，透疹</td><td style="text-align:left;">风热、疹痒</td></tr></tbody></table><h3 id="_2-痹证论治" tabindex="-1">2. 痹证论治 <a class="header-anchor" href="#_2-痹证论治" aria-label="Permalink to &quot;2. 痹证论治&quot;">​</a></h3><blockquote><p><strong>「痹证，风寒湿三气杂至，合而为痹。」</strong></p></blockquote><p>朱良春对类风湿关节炎、强直性脊柱炎等风湿免疫类疾病有极深造诣：</p><ul><li>急性期：清热通络（虫类药为主）</li><li>慢性期：补肝肾、强筋骨</li></ul><h3 id="_3-健脾胃法" tabindex="-1">3. 健脾胃法 <a class="header-anchor" href="#_3-健脾胃法" aria-label="Permalink to &quot;3. 健脾胃法&quot;">​</a></h3><blockquote><p><strong>「脾胃为后天之本，万病当以脾胃为先。」</strong></p></blockquote><p>朱良春善用<strong>健脾胃法</strong>治疗各种疑难杂病。</p><h3 id="_4-毒药攻邪" tabindex="-1">4. 毒药攻邪 <a class="header-anchor" href="#_4-毒药攻邪" aria-label="Permalink to &quot;4. 毒药攻邪&quot;">​</a></h3><p>朱良春对有毒中药（马钱子、乌头、斑蝥等）的炮制和用量有独到经验。</p><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>痛风冲剂</strong></td><td style="text-align:left;">土茯苓、萆薢、威灵仙、秦艽、泽泻、地龙等</td><td style="text-align:left;">痛风</td></tr><tr><td style="text-align:left;"><strong>益肾蠲痹丸</strong></td><td style="text-align:left;">熟地、当归、淫羊藿、鹿衔草、全蝎、蜈蚣、地龙</td><td style="text-align:left;">类风湿关节炎</td></tr><tr><td style="text-align:left;"><strong>健胃散</strong></td><td style="text-align:left;">党参、白术、茯苓、甘草、陈皮、砂仁、鸡内金</td><td style="text-align:left;">脾胃虚弱</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「虫类药是中医药宝库中的瑰宝。」</strong></p></blockquote><blockquote><p><strong>「痹证，风寒湿三气杂至，合而为痹。」</strong></p></blockquote><blockquote><p><strong>「脾胃为后天之本，万病当以脾胃为先。」</strong></p></blockquote><blockquote><p><strong>「中医不能固步自封，要善于吸收新知。」</strong></p></blockquote><blockquote><p><strong>「顽病多瘀，久病入络。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li>虫类药在肿瘤、风湿、心脑血管等疑难病中的广泛应用</li><li>益肾蠲痹丸是类风湿关节炎的常用中成药</li><li>&quot;久病入络&quot;理论被广泛接受</li></ul><hr><p><em>本条目为精简框架版。可扩展至虫类药应用指南、痹证辨证体系等专题。</em></p>',34)])])}const u=e(r,[["render",n]]);export{x as __pageData,u as default};
